chart.options:
chart: {
  type: 'bar',
  height: 380,
  toolbar: {
    show: false
  },
  animations: {
    enabled: true,
    speed: 800,
    chartTypeMorph: {
      enabled: true,
      speed: 700,
    },
  },
},
grid: {
  show: false
},
labels: ['Direct', 'Organic', 'Referral', 'Social', 'Email'],
legend: { position: 'bottom' },
plotOptions: {
  bar: {
    borderRadius: 4,
    columnWidth: '52%',
    distributed: true,
  },
  radialBar: {
    inverseOrder: true,
    hollow: {
      size: '5%'
    },
    track: {
      show: false
    }
  },
  funnel: {
    shape: 'trapezoid',
  },
},
yaxis: {
  show: false,
  axisBorder: {
    show: false,
  }
},
xaxis: {
  labels: {
      show: false
  },
  axisBorder: {
    show: false,
  },
  axisTicks: {
    show: false,
  }
},
dataLabels: { enabled: false },
fill: {
  opacity: 0.9
},
stroke: {  lineCap: 'butt', width: 1, colors: ['#fff'] },

vanilla-js-script:
var LABELS = ['Direct', 'Organic', 'Referral', 'Social', 'Email']
var currentType = 'bar'
var currentHorizontal = false
var currentValues = [44, 55, 41, 27, 33]
var currentBarHeight = 70

function buildSeriesFor(type, values) {
  if (type === 'funnel') {
    var sorted = values.slice().sort(function (a, b) { return b - a })
    return [{ name: 'Sessions', data: sorted }]
  }
  if (type === 'bar' || type === 'pyramid') {
    return [{ name: 'Sessions', data: values.slice() }]
  }
  return values.slice()
}

function setActive(type, horizontal) {
  document.querySelectorAll('.actions button[data-type]').forEach(function (btn) {
    var btnType = btn.getAttribute('data-type')
    var btnH = btn.getAttribute('data-horizontal')
    var active =
      btnType === type &&
      (type !== 'bar' || String(horizontal) === btnH)
    btn.classList.toggle('active', active)
  })
}
setActive(currentType, currentHorizontal)

document.querySelectorAll('.actions button[data-type]').forEach(function (btn) {
  btn.addEventListener('click', function () {
    var nextType = btn.getAttribute('data-type')
    var nextHorizontal = btn.getAttribute('data-horizontal') === 'true'
    if (nextType === currentType && nextHorizontal === currentHorizontal) return
    currentType = nextType
    currentHorizontal = nextHorizontal
    setActive(currentType, currentHorizontal)
    chart.updateOptions({
      chart: { type: currentType },
      plotOptions: {
        bar: {
          horizontal: currentHorizontal,
          barHeight: currentBarHeight + '%',
        },
      },
      series: buildSeriesFor(currentType, currentValues),
      labels: LABELS,
    })
  })
})

document.querySelector('#randomize').addEventListener('click', function () {
  currentValues = currentValues.map(function () {
    return Math.floor(Math.random() * 80) + 10
  })
  chart.updateSeries(buildSeriesFor(currentType, currentValues))
})

var speedInput = document.querySelector('#speed')
var speedValue = document.querySelector('#speed-value')
speedInput.addEventListener('input', function () {
  var v = parseInt(speedInput.value, 10)
  speedValue.textContent = v
  chart.updateOptions(
    { chart: { animations: { chartTypeMorph: { speed: v } } } },
    false,
    false,
  )
})

var barHeightInput = document.querySelector('#bar-height')
var barHeightValue = document.querySelector('#bar-height-value')
barHeightInput.addEventListener('input', function () {
  var v = parseInt(barHeightInput.value, 10)
  barHeightValue.textContent = v
  currentBarHeight = v
  chart.updateOptions(
    { plotOptions: { bar: { barHeight: v + '%' } } },
    false,
    false,
  )
})
